package com.trademaster.ims.mobile.shopping.controller;
import com.trademaster.ims.mobile.shopping.dto.ShoppingDtos.*; import com.trademaster.ims.mobile.shopping.service.CustomerShoppingService; import jakarta.servlet.http.HttpServletRequest; import jakarta.validation.Valid; import org.springframework.security.core.Authentication; import org.springframework.web.bind.annotation.*;
@RestController @RequestMapping("/api/mobile/v1") public class CustomerShoppingController {
 private final CustomerShoppingService service; public CustomerShoppingController(CustomerShoppingService s){service=s;} private Long account(Authentication a){return service.accountId(a);}
 @GetMapping("/cart") CartResponse cart(Authentication a,HttpServletRequest r){return service.getCart(account(a),r);} @PostMapping("/cart/items") CartResponse add(Authentication a,@Valid @RequestBody AddCartItemRequest b,HttpServletRequest r){return service.addCartItem(account(a),b,r);} @PutMapping("/cart/items/{id}") CartResponse update(Authentication a,@PathVariable Long id,@Valid @RequestBody UpdateCartItemQuantityRequest b,HttpServletRequest r){return service.updateCartItem(account(a),id,b,r);} @DeleteMapping("/cart/items/{id}") CartResponse remove(Authentication a,@PathVariable Long id,HttpServletRequest r){return service.removeCartItem(account(a),id,r);} @DeleteMapping("/cart") CartResponse clear(Authentication a,HttpServletRequest r){return service.clearCart(account(a),r);} @PostMapping("/cart/merge-session") CartResponse merge(Authentication a,@Valid @RequestBody MergeSessionCartRequest b,HttpServletRequest r){return service.mergeCart(account(a),b,r);} @PostMapping("/cart/validate") CartResponse validate(Authentication a,HttpServletRequest r){return service.validateCart(account(a),r);}
 @GetMapping("/wishlist") WishlistResponse wishlist(Authentication a,HttpServletRequest r){return service.getWishlist(account(a),r);} @PostMapping("/wishlist/items") WishlistResponse addWishlist(Authentication a,@Valid @RequestBody AddWishlistItemRequest b,HttpServletRequest r){return service.addWishlist(account(a),b,r);} @DeleteMapping("/wishlist/items/{productId}") WishlistResponse removeWishlist(Authentication a,@PathVariable Long productId,HttpServletRequest r){return service.removeWishlist(account(a),productId,r);} @DeleteMapping("/wishlist") WishlistResponse clearWishlist(Authentication a,HttpServletRequest r){return service.clearWishlist(account(a),r);} @PostMapping("/wishlist/merge-session") WishlistResponse mergeWishlist(Authentication a,@Valid @RequestBody MergeSessionWishlistRequest b,HttpServletRequest r){return service.mergeWishlist(account(a),b,r);}
}
